// 한줄 지시에서 유형과 주제를 파싱
const input = $input.first().json;
const body = input.body || input;
const instruction = (body.instruction || body.text || '').trim();

if (!instruction) {
  return [{ json: { error: '기획안 지시가 비어있습니다.', success: false } }];
}

// 유형 자동 판별
let prdType = 'product-detail';
let typeName = '상품 상세페이지';

const lower = instruction.toLowerCase();
if (/이벤트|할인|프로모션|기획전|쿠폰/.test(lower)) {
  prdType = 'event-promo';
  typeName = '이벤트/프로모션';
} else if (/랜딩|모집|소개|브랜드페이지/.test(lower)) {
  prdType = 'landing-page';
  typeName = '랜딩 페이지';
} else if (/인스타|유튜브|블로그|sns|릴스|숏츠|포스트/.test(lower)) {
  prdType = 'sns-content';
  typeName = 'SNS 콘텐츠';
} else if (/상세페이지|상품|신상품/.test(lower)) {
  prdType = 'product-detail';
  typeName = '상품 상세페이지';
}

// "기획안" prefix 제거 후 주제 추출
const topic = instruction.replace(/^기획안\s*/, '').replace(/^(상세페이지|이벤트|할인|프로모션|랜딩|인스타|유튜브|블로그|SNS|릴스)\s*/, '').trim() || instruction;

const requestedBy = body.requested_by || body.user || '대표';
const now = new Date();
const kstDate = new Date(now.getTime() + 9 * 60 * 60 * 1000).toISOString().slice(0, 10);

return [{
  json: {
    instruction,
    prdType,
    typeName,
    topic,
    requestedBy,
    kstDate,
    success: true
  }
}];

// Claude API 응답에서 기획안 텍스트 추출
const input = $input.first().json;
const prev = $('입력 파싱').first().json;

let content = '';
if (input.content && Array.isArray(input.content)) {
  content = input.content
    .filter(b => b.type === 'text')
    .map(b => b.text)
    .join('\n');
} else if (typeof input === 'string') {
  content = input;
}

// 제목 추출 (첫 ## 라인)
const titleMatch = content.match(/^##\s+(.+)/m);
const title = titleMatch ? titleMatch[1].trim() : prev.topic;

return [{
  json: {
    title,
    prd_type: prev.prdType,
    type_name: prev.typeName,
    instruction: prev.instruction,
    content_md: content,
    requested_by: prev.requestedBy,
    status: 'draft',
    created_date: prev.kstDate
  }
}];

// 텔레그램 알림 메시지 구성
const prd = $('기획안 텍스트 추출').first().json;
const nocoResult = $input.first().json;
const rowId = nocoResult.Id || nocoResult.id || '?';

// 기획안 미리보기 (첫 500자)
const preview = prd.content_md.slice(0, 500).replace(/[<>&]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c]));

const msg = [
  `<b>[기획안 생성 완료]</b>`,
  ``,
  `<b>제목</b>: ${prd.title}`,
  `<b>유형</b>: ${prd.type_name}`,
  `<b>요청</b>: ${prd.instruction}`,
  `<b>상태</b>: draft (승인 대기)`,
  `<b>NocoDB ID</b>: #${rowId}`,
  ``,
  `<b>미리보기</b>:`,
  `<pre>${preview}...</pre>`,
  ``,
  `NocoDB에서 전문 확인 후 승인해주세요.`
].join('\n');

return [{ json: { message: msg, rowId } }];
